record_types.code:
type ex_info is record
   vector   : word;
   priority : byte;
   timeout  : byte;
end record;

type features is record
   has_extra : Boolean;
   has_RTT   : Boolean;
   has_EIS   : Boolean;
   has_FIS   : Boolean;
   has_FPP   : Boolean;
   has_CIS   : Boolean;
   has_user  : Boolean;
   has_super : Boolean;
   has_ID    : Boolean;
   has_MMU18 : Boolean;
   has_MMU22 : Boolean;
   has_MTFPS : Boolean;
   SWAB_V    : Boolean;
   set_PSW_T : Boolean;
   reg_value : Boolean;
   reg_bus   : Boolean;
   stack_limit : word;
end record;
